SELECT g.id, g.student_id, g.course_id, g.course_name, g.teacher_id, g.attendance_score, g.homework_score, g.quiz_score, g.exam_score, g.final_score, g.grade_level, g.gpa, g.credit_earned, g.is_pass, g.published_time, g.created_time FROM grade g
AND g.student_id = #{q.studentId}
AND g.course_id = #{q.courseId}
AND g.is_pass = #{q.isPass}
AND g.published_time IS NOT NULL
ORDER BY g.published_time DESC, g.created_time DESC

SELECT g.id, g.student_id, g.course_id, g.course_name, g.teacher_id, g.attendance_score, g.homework_score, g.quiz_score, g.exam_score, g.final_score, g.grade_level, g.gpa, g.credit_earned, g.is_pass, g.published_time, g.created_time FROM grade g
g.course_id = #{courseId}
AND g.student_id = #{q.studentId}
AND g.is_pass = #{q.isPass}
AND g.published_time IS NOT NULL
AND g.published_time IS NULL
ORDER BY g.created_time DESC, g.id DESC

